"use client"

import * as React from "react"
import { CheckIcon } from "lucide-react"

import { cn } from "@/lib/utils"

// ─── Types ─────────────────────────────────────────────────────────────────────

type StepperOrientation = "horizontal" | "vertical"
type StepStatus = "completed" | "active" | "pending"

// ─── StepperContext ────────────────────────────────────────────────────────────

type StepperContextValue = {
  value: string
  onValueChange: (value: string) => void
  orientation: StepperOrientation
  steps: string[]
  registerStep: (value: string) => () => void
}

const StepperContext = React.createContext<StepperContextValue | null>(null)

function useStepper() {
  const context = React.useContext(StepperContext)
  if (!context) {
    throw new Error("useStepper must be used within a <Stepper />")
  }
  return context
}

// ─── StepperItemContext ────────────────────────────────────────────────────────

type StepperItemContextValue = {
  value: string
  status: StepStatus
  disabled: boolean
}

const StepperItemContext =
  React.createContext<StepperItemContextValue | null>(null)

function useStepperItem() {
  const context = React.useContext(StepperItemContext)
  if (!context) {
    throw new Error("useStepperItem must be used within a <StepperItem />")
  }
  return context
}

// ─── Stepper ───────────────────────────────────────────────────────────────────

type StepperProps = React.ComponentProps<"div"> & {
  /** The controlled value of the active step. */
  value?: string
  /** The initial value of the active step when uncontrolled. */
  defaultValue?: string
  /** Called when the active step changes. */
  onValueChange?: (value: string) => void
  /** Layout direction of the stepper. @default "horizontal" */
  orientation?: StepperOrientation
}

function Stepper({
  value,
  defaultValue = "",
  onValueChange,
  orientation = "horizontal",
  className,
  children,
  ...props
}: StepperProps) {
  const [internalValue, setInternalValue] = React.useState(defaultValue)
  const [steps, setSteps] = React.useState<string[]>([])

  const isControlled = value !== undefined
  const currentValue = isControlled ? value : internalValue

  const handleValueChange = React.useCallback(
    (newValue: string) => {
      if (!isControlled) setInternalValue(newValue)
      onValueChange?.(newValue)
    },
    [isControlled, onValueChange]
  )

  const registerStep = React.useCallback((stepValue: string) => {
    setSteps((prev) =>
      prev.includes(stepValue) ? prev : [...prev, stepValue]
    )
    return () => setSteps((prev) => prev.filter((s) => s !== stepValue))
  }, [])

  return (
    <StepperContext.Provider
      value={{
        value: currentValue,
        onValueChange: handleValueChange,
        orientation,
        steps,
        registerStep,
      }}
    >
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn(
          "flex",
          orientation === "horizontal"
            ? "flex-row flex-wrap items-start"
            : "flex-col",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperContext.Provider>
  )
}

// ─── StepperItem ───────────────────────────────────────────────────────────────

type StepperItemProps = React.ComponentProps<"div"> & {
  /** Unique identifier for this step. Must match a StepperPanel value to show content. */
  value: string
  /** Prevents the user from clicking this step's trigger. */
  disabled?: boolean
}

function StepperItem({
  value,
  disabled = false,
  className,
  children,
  ...props
}: StepperItemProps) {
  const {
    value: currentValue,
    orientation,
    steps,
    registerStep,
  } = useStepper()

  // Register this step so the stepper knows the ordered list of step values.
  // useLayoutEffect ensures registration happens before the browser paints,
  // avoiding a flash of incorrect step status on first render.
  React.useLayoutEffect(() => {
    return registerStep(value)
  }, [value, registerStep])

  const stepIndex = steps.indexOf(value)
  const currentIndex = steps.indexOf(currentValue)

  const status: StepStatus =
    stepIndex === -1 || currentIndex === -1
      ? "pending"
      : stepIndex < currentIndex
        ? "completed"
        : stepIndex === currentIndex
          ? "active"
          : "pending"

  return (
    <StepperItemContext.Provider value={{ value, status, disabled }}>
      <div
        data-slot="stepper-item"
        data-status={status}
        data-orientation={orientation}
        data-disabled={disabled || undefined}
        className={cn(
          "group/step flex items-start",
          orientation === "horizontal"
            ? "min-w-0 flex-1 flex-row"
            : "w-full flex-col",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperItemContext.Provider>
  )
}

// ─── StepperTrigger ────────────────────────────────────────────────────────────

function StepperTrigger({
  className,
  onClick,
  children,
  ...props
}: React.ComponentProps<"button">) {
  const { onValueChange } = useStepper()
  const { value, status, disabled } = useStepperItem()

  return (
    <button
      type="button"
      data-slot="stepper-trigger"
      data-status={status}
      aria-current={status === "active" ? "step" : undefined}
      disabled={disabled}
      onClick={(e) => {
        onValueChange(value)
        onClick?.(e)
      }}
      className={cn(
        "inline-flex cursor-pointer items-center gap-2 rounded-sm text-sm outline-none transition-colors",
        "focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2",
        "disabled:pointer-events-none disabled:opacity-50",
        className
      )}
      {...props}
    >
      {children}
    </button>
  )
}

// ─── StepperIndicator ──────────────────────────────────────────────────────────

function StepperIndicator({
  className,
  children,
  ...props
}: React.ComponentProps<"span">) {
  const { steps } = useStepper()
  const { value, status } = useStepperItem()

  // 1-based step number; falls back to 0 when not yet registered.
  const stepNumber = steps.indexOf(value) + 1

  return (
    <span
      data-slot="stepper-indicator"
      data-status={status}
      className={cn(
        "flex size-7 shrink-0 select-none items-center justify-center rounded-full border-2 text-xs font-semibold transition-all",
        status === "completed" &&
          "border-primary bg-primary text-primary-foreground",
        status === "active" && "border-primary bg-background text-primary",
        status === "pending" &&
          "border-border bg-background text-muted-foreground",
        className
      )}
      {...props}
    >
      {children ??
        (status === "completed" ? (
          <CheckIcon className="size-3.5" aria-hidden />
        ) : (
          stepNumber || "·"
        ))}
    </span>
  )
}

// ─── StepperTitle ──────────────────────────────────────────────────────────────

function StepperTitle({ className, ...props }: React.ComponentProps<"p">) {
  const { status } = useStepperItem()

  return (
    <p
      data-slot="stepper-title"
      data-status={status}
      className={cn(
        "text-sm font-medium leading-none",
        status === "active" ? "text-foreground" : "text-muted-foreground",
        className
      )}
      {...props}
    />
  )
}

// ─── StepperDescription ────────────────────────────────────────────────────────

function StepperDescription({
  className,
  ...props
}: React.ComponentProps<"p">) {
  const { status } = useStepperItem()

  return (
    <p
      data-slot="stepper-description"
      data-status={status}
      className={cn("text-xs text-muted-foreground", className)}
      {...props}
    />
  )
}

// ─── StepperSeparator ──────────────────────────────────────────────────────────

function StepperSeparator({
  className,
  ...props
}: React.ComponentProps<"div">) {
  const { orientation, steps } = useStepper()
  const { value, status } = useStepperItem()

  // The last registered step has no following step to connect to.
  const isLastStep =
    steps.length > 0 && steps[steps.length - 1] === value

  if (isLastStep) return null

  return (
    <div
      aria-hidden
      data-slot="stepper-separator"
      data-status={status}
      className={cn(
        "shrink-0 rounded-full bg-border transition-colors",
        // Horizontal: fill remaining horizontal space in the StepperItem row,
        // vertically centred with the StepperIndicator (size-7 = 28 px → 14 px centre → self-center).
        orientation === "horizontal"
          ? "mx-2 h-0.5 flex-1 self-center"
          : // Vertical: thin vertical rule that sits below the trigger,
            // offset by 13 px to align with the centre of the size-7 indicator.
            "my-1 ms-[13px] w-0.5 min-h-6",
        status === "completed" && "bg-primary",
        className
      )}
      {...props}
    />
  )
}

// ─── StepperPanel ──────────────────────────────────────────────────────────────

type StepperPanelProps = React.ComponentProps<"div"> & {
  /** The step value whose content this panel displays. */
  value: string
}

function StepperPanel({ value, className, ...props }: StepperPanelProps) {
  const { value: currentValue, orientation } = useStepper()

  if (value !== currentValue) return null

  return (
    <div
      data-slot="stepper-panel"
      role="tabpanel"
      className={cn(
        "mt-6",
        // In horizontal flex-wrap layout, basis-full forces the panel onto its
        // own row so it spans the full width beneath the step items.
        orientation === "horizontal" && "basis-full",
        className
      )}
      {...props}
    />
  )
}

// ─── Exports ───────────────────────────────────────────────────────────────────

export {
  type StepperOrientation,
  type StepStatus,
  Stepper,
  StepperItem,
  StepperTrigger,
  StepperIndicator,
  StepperTitle,
  StepperDescription,
  StepperSeparator,
  StepperPanel,
  useStepper,
  useStepperItem,
}
